    statement: { description: "## Multiply Large Number Strings\n\nGiven two non-negative integers `num1` and `num2` represented as strings, return their product as a string.\n\nYou must not use any built-in BigInteger library or convert the inputs to integers directly.", inputFormat: "Two lines, each containing a numeric string.", outputFormat: "Print the product as a string.", constraints: "1 ≤ |num1|, |num2| ≤ 200\nBoth contain only digits.\nNo leading zeros except the number 0 itself.", notes: "" },
    samples: [ { input: "2\n3", output: "6", explanation: "2 × 3 = 6." }, { input: "123\n456", output: "56088", explanation: "123 × 456 = 56088." }, { input: "0\n0", output: "0", explanation: "0 × 0 = 0." } ],
