    statement: { description: "## Decode Bracket-Encoded String\n\nGiven an encoded string like `3[a2[c]]`, decode it. The encoding rule is: `k[encoded_string]` means the `encoded_string` inside the brackets is repeated `k` times.\n\nYou may assume the input is always valid.", inputFormat: "A single line containing the encoded string.", outputFormat: "Print the decoded string.", constraints: "1 ≤ |s| ≤ 300\n`s` contains digits, lowercase letters, '[', ']'.\n1 ≤ k ≤ 300", notes: "" },
    samples: [ { input: "3[a]2[bc]", output: "aaabcbc", explanation: "3×'a' + 2×'bc' = 'aaabcbc'." }, { input: "3[a2[c]]", output: "accaccacc", explanation: "Inner: 2×'c'='cc'. Then 'acc'. Outer: 3×'acc'." }, { input: "2[abc]3[cd]ef", output: "abcabccdcdcdef", explanation: "2×'abc' + 3×'cd' + 'ef'." } ],
    hiddenTestCases: [ { input: "a", output: "a" }, { input: "1[a]", output: "a" }, { input: "10[a]", output: "aaaaaaaaaa" }, { input: "2[2[b]]", output: "bbbb" }, { input: "abc", output: "abc" }, { input: "3[z]2[y]x", output: "zzzyyx" }, { input: "1[1[1[a]]]", output: "a" }, { input: "2[ab3[c]]", output: "abcccabccc" }, { input: "100[a]", output: "a".repeat(100) }, { input: "2[a2[b]]3[c]", output: "abbabbccc" } ],
