    statement: { description: "## String Interleaving Validator\n\nGiven strings `s1`, `s2`, and `s3`, determine if `s3` is formed by an interleaving of `s1` and `s2`.\n\nAn interleaving preserves the relative order of characters from each string.", inputFormat: "Three lines, each containing a string.", outputFormat: "Print `true` or `false`.", constraints: "0 ≤ |s1|, |s2| ≤ 100\n0 ≤ |s3| ≤ 200\nOnly lowercase English letters.", notes: "" },
